import logo from './logo.svg';
import './App.css';

function App() {
  return (
    <div className="App">
      <div className='form'>

        <input type='text' placeholder='Enter Your Name'></input><br/>

        <input type='text' placeholder='Enter Your Phone Number'></input><br/>

        <input type='text' placeholder='Enter Your Age'></input><br/>

        <label><input type='checkbox'/></label>
      </div>
    </div>
  );
}

export default App;
